function MiniDonut({ items, label = "\u603B\u6570", total = "174" }: {
    items: Array<{
        color: string;
        value: number;
        label: string;
        percent: string;
    }>;
    label?: string;
    total?: string;
}) { let cursor = 0; const segments = items.map(item => { const next = cursor + Math.max(4, (item.value / 174) * 100); const segment = `${item.color} ${cursor}% ${Math.min(100, next)}%`; cursor = next; return segment; }).join(", "); return (<div className="coal-basic-donut-block">      <div className="coal-basic-donut" style={{ "--donut-segments": segments } as React.CSSProperties}>        <b>{total}</b>        <span>{label}</span>      </div>      <div className="coal-basic-donut-legend">        {items.map(item => (<span key={`${item.label}-${item.value}`}>            <i style={{ background: item.color }}/>            {item.label}            <b>{item.value}</b>            <em>{item.percent}</em>          </span>))}      </div>    </div>); }
