function HiddenFaceMineProfilePage() {
    const data = shuanHiddenFaceMineProfileData;
    const scorePercent = Math.max(0, Math.min(100, data.mine.score));
    const weightedScore = data.scoreParts.slice(0, 2).reduce((sum, part) => sum + part.value, 0);
    const feedbackDeduction = Math.abs(data.scoreParts[2]?.value ?? 0);
    const [activeSection, setActiveSection] = useState(data.catalog[0]?.id ?? "");
    useEffect(() => {
        const sections = data.catalog.map(item => document.getElementById(item.id)).filter((section): section is HTMLElement => Boolean(section));
        const observer = new IntersectionObserver(entries => {
            const current = entries.filter(entry => entry.isIntersecting).sort((left, right) => Math.abs(left.boundingClientRect.top) - Math.abs(right.boundingClientRect.top))[0];
            if (current)
                setActiveSection(current.target.id);
        }, { rootMargin: "-16% 0px -62%", threshold: 0 });
        sections.forEach(section => observer.observe(section));
        return () => observer.disconnect();
    }, [data.catalog]);
    const scrollToSection = (event: React.MouseEvent<HTMLAnchorElement>, sectionId: string) => { event.preventDefault(); setActiveSection(sectionId); document.getElementById(sectionId)?.scrollIntoView({ behavior: "smooth", block: "start" }); };
    return (<div className="drill-page drill-mine-profile-page">      <aside className="drill-mine-profile-toc" aria-label="页内目录">        <a className="drill-mine-profile-back" href={routeHref("shuan-home-command-v3-illegal-campaign-hidden-face")}>          <ArrowLeft aria-hidden="true"/>          <span>返回专题整治</span>        </a>        <nav>          {data.catalog.map(item => (<a key={item.id} href={`#${item.id}`} className={activeSection === item.id ? "active" : ""} aria-current={activeSection === item.id ? "location" : undefined} onClick={event => scrollToSection(event, item.id)}>              <strong>{item.label}</strong>              {item.children ? <span>{item.children.join(" / ")}</span> : null}            </a>))}        </nav>      </aside>      <main className="drill-mine-profile-main">        <header className="drill-mine-profile-titlebar">          <div>            <p>隐蔽工作面专项整治/ 三级煤矿画像</p>            <h1>{data.title}</h1>            <span>{data.subtitle}</span>          </div>          <div className="drill-mine-profile-actions">              <span>数据更新时间：{data.updatedAt}</span>            <button type="button"><RefreshCcw aria-hidden="true"/>刷新</button>          </div>        </header>        <section id="mine-overview" className="drill-mine-profile-section" style={{ scrollMarginTop: 24 }}>          <h2>煤矿概况</h2>          <div className="drill-mine-profile-overview-grid">            <article className="drill-mine-profile-card mine-id">              <span>煤矿名称</span>              <strong>{data.mine.name}</strong>              <p>{data.mine.company}</p>              <em>{data.mine.location}</em>              <b>{data.mine.productionStatus}</b>            </article>            <article className="drill-mine-profile-card score-card">              <span>综合风险得分</span>              <strong>{data.mine.score}</strong>              <p>/100</p>              <em>较上次 {data.mine.previousDelta} →</em>            </article>            <article className="drill-mine-profile-card level-card">              <span>风险等级</span>              <strong>{data.mine.level}</strong>              <b>{data.mine.levelReason}</b>            </article>            <article className="drill-mine-profile-card">              <span>区域排名</span>              <strong>{data.mine.regionRank}</strong>              <p>同区域排名</p>            </article>            <article className="drill-mine-profile-card">              <span>有效线索数</span>              <strong>{data.mine.validClues}</strong>              <p>较上次 +23</p>            </article>          </div>          <div className="drill-mine-profile-status-strip">            <span><em>计分线索</em><strong>{data.mine.scoringClues}</strong><b>占比 {data.mine.scoringRatio}</b></span>            <span><em>最新评分时间</em><strong>{data.mine.lastScoreTime}</strong><b>每日更新</b></span>            <span><em>最近核查状态</em><strong>{data.mine.verificationStatus}</strong><b>{data.mine.verificationProgress}</b></span>            <span><em>最新反馈结论</em><strong>{data.mine.feedbackConclusion}</strong><b>{data.mine.pendingIssues}</b></span>          </div>          <article className="drill-mine-profile-panel score-breakdown">            <header>              <h3>综合评分</h3>            </header>            <div className="drill-mine-profile-score-layout">              <div className="drill-mine-profile-donut" style={{ "--score": `${scorePercent * 3.6}deg` } as React.CSSProperties}>                <img src={hiddenFaceScoreShield} alt="" aria-hidden="true"/>                <span>综合风险得分</span>                <strong>{data.mine.score}</strong>                <em>/100</em>                <b>{data.mine.level}</b>              </div>              <div className="drill-mine-profile-score-bars">                <div className="drill-mine-profile-score-flow" aria-label={`模型风险分 ${weightedScore.toFixed(1)}，回流修正减 ${feedbackDeduction.toFixed(1)}，当前风险分 ${data.mine.score}`}>                  <section><span>线索基础</span><strong>41.7</strong><em>原始分 83.3 × 50%</em></section>                  <b aria-hidden="true">＋</b>                  <section><span>关联增强</span><strong>38.5</strong><em>原始分 77.0 × 50%</em></section>                  <b aria-hidden="true">＝</b>                  <section><span>模型风险分</span><strong>{weightedScore.toFixed(1)}</strong><em>加权汇总</em></section>                  <b className="is-deduction" aria-hidden="true">−</b>                  <section className="is-deduction"><span>回流修正</span><strong>{feedbackDeduction.toFixed(1)}</strong><em>回流结果修正</em></section>                  <b aria-hidden="true">＝</b>                  <section className="is-final"><span>当前风险分</span><strong>{data.mine.score}</strong><em>最终结果</em></section>                </div>                <div className="drill-mine-profile-waterfall" aria-hidden="true">                  <div className="waterfall-track">                    <span className="base" style={{ width: "41.7%" }}/>                    <span className="association" style={{ left: "41.7%", width: "38.5%" }}/>                    <span className="adjustment" style={{ left: "74.9%", width: "5.3%" }}/>                  </div>                  <div className="waterfall-axis">                    {[0, 20, 40, 60, 80, 100].map(tick => <span key={tick} style={{ left: `${tick}%` }}>{tick}</span>)}                  </div>                  <i className="base-marker" style={{ left: "41.7%" }}/>                  <i className="model-marker" style={{ left: "80.2%" }}/>                  <i className="current-marker" style={{ left: "74.9%" }}/>                  <div className="waterfall-label base-label">                    <strong>41.7</strong><span>线索基础加权得分</span><em>（0 → 41.7）</em>                  </div>                  <div className="waterfall-label model-label">                    <strong>80.2</strong><span>模型风险分</span><em>（41.7 + 38.5）</em>                  </div>                  <div className="waterfall-label adjustment-label">                    <strong>-5.3</strong><span>回流修正</span><em>（80.2 → 74.9）</em>                  </div>                  <div className="waterfall-label current-label">                    <strong>74.9</strong><span>当前风险分</span><em>（80.2 - 5.3）</em>                  </div>                </div>              </div>            </div>            <p className="drill-mine-profile-score-note">回流修正依据现场核查、执法处置及整改闭环结果，经审核后计入当前评分。</p>          </article>        </section>        <section id="risk-profile" className="drill-mine-profile-section" style={{ scrollMarginTop: 24 }}>          <h2>风险画像</h2>          <article className="drill-mine-profile-panel">            <h3>算法线索贡献</h3>            <div className="drill-mine-profile-category-grid">              {data.algorithmContributions.map(item => { const Icon = mineProfileCategoryIcon[item.icon]; return (<section key={item.category}>                    <header><Icon aria-hidden="true"/><strong>{item.category}</strong></header>                    <p><span>线索数</span><b>{item.hit}</b><em>条</em></p>                    <p><span>计分线索</span><b>{item.scored}</b><em>条</em></p>                    <p><span>线索贡献分</span><b>{item.contribution}</b></p>                    <dl>                      <dt>代表算法</dt>                      <dd>{item.algorithm}</dd>                      <dt>异常摘要</dt>                      <dd>{item.summary}</dd>                    </dl>                  </section>); })}            </div>          </article>          <article className="drill-mine-profile-panel">            <h3>关键线索</h3>            <div className="drill-mine-profile-clue-table">              <div className="head">{["\u5E8F\u53F7", "\u5173\u952E\u7EBF\u7D22", "\u6765\u6E90\u7B97\u6CD5", "\u65F6\u95F4", "\u533A\u57DF/\u5BF9\u8C61", "\u98CE\u9669\u7B49\u7EA7", "\u6570\u636E\u53EF\u4FE1\u5EA6", "\u8D21\u732E\u5206", "\u64CD\u4F5C"].map(item => <span key={item}>{item}</span>)}</div>              {data.keyClues.map((row, index) => (<div key={row.id}>                  <span>{index + 1}</span>                  <span>{row.title}</span>                  <span>{row.source}</span>                  <span>{row.time}</span>                  <span>{row.area}</span>                  <span><MineProfileTag level={row.risk}/></span>                  <span>{row.confidence}</span>                  <span>{row.score}</span>                  <span className="actions"><button type="button">查看</button></span>                </div>))}            </div>          </article>          <article className='drill-mine-profile-panel association'>
            <header className='drill-mine-profile-association-head'><h3>关联增强分析</h3></header>
            <div className='drill-mine-profile-association-cards'>
              <section className='drill-mine-profile-association-summary'><header><span>关联得分汇总</span></header><p>原始分 <b>77.0</b>，50%权重计入 <strong>38.5</strong> 分</p><div><em>增益 <b>+20.7</b></em><em>质量修正 <b>-0.6</b></em></div><footer><span>关联增强净分</span><b>+20.1</b></footer></section>
              {mineProfileAssociationAlgorithms.map((item) => (<section key={item.name} className={item.score.startsWith('-') ? 'is-correction' : ''}><header><span><ShieldAlert aria-hidden='true' /><strong>{item.name}</strong></span><MineProfileTag level={item.level} /></header><div><span>输出指标</span><em>{item.output}</em></div><footer><span>{item.result}</span><b>{item.score}</b></footer></section>))}
            </div>

          </article>        </section>        <section id="verification-loop" className="drill-mine-profile-section" style={{ scrollMarginTop: 24 }}>          <h2>核查闭环</h2>          <div className="drill-mine-profile-verification-grid">            <article className="drill-mine-profile-panel summary">              <h3>核查要点</h3>              <p>{data.verification.summary}</p>            </article>            <article className="drill-mine-profile-panel checklist">              <h3>核查重点清单</h3>              {data.verification.checklist.map(item => (<p key={item.text}><i />{item.text}<MineProfileTag level={item.level}/></p>))}            </article>            <article className="drill-mine-profile-panel priority">              <h3>优先核查区域</h3>              {data.verification.priorityAreas.map((item, index) => <p key={item}><b>{index + 1}</b>{item}</p>)}            </article>            <article className="drill-mine-profile-panel priority">              <h3>优先核查对象</h3>              {data.verification.priorityObjects.map((item, index) => <p key={item}><b>{index + 1}</b>{item}</p>)}            </article>            <article className="drill-mine-profile-panel evidence">              <h3>关键证据重点</h3>              <div>{data.verification.evidence.map(item => <span key={item}>{item}</span>)}</div>            </article>          </div>          <article className="drill-mine-profile-panel feedback">            <h3>最近任务与回流</h3>            <div className="drill-mine-profile-feedback-grid">              <div className="timeline">                {data.feedback.timeline.map((item, index) => (<span key={item.label} className={index === data.feedback.timeline.length - 1 ? "active" : ""}>                    <i>{index + 1}</i>                    <strong>{item.label}</strong>                    <em>{item.time}</em>                  </span>))}              </div>              <div className="score-change">                <span>回流效果（本次）</span>                <p><b>{data.feedback.beforeScore}</b><ChevronRight aria-hidden="true"/><strong>{data.feedback.afterScore}</strong></p>                <em>修正值 {data.feedback.correction}</em>              </div>              <div className="level-change">                <span>风险等级变化</span>                <strong>{data.feedback.levelChange}</strong>                <b>维持不变</b>              </div>              <div className="follow-up">                <span>后续跟踪</span>                <p>{data.feedback.followUp}</p>                <button type="button">生成跟踪任务</button>              </div>            </div>            <div className="drill-mine-profile-task-table">              <div className="head">{["\u4EFB\u52A1\u7F16\u53F7", "\u4EFB\u52A1\u540D\u79F0", "\u4EFB\u52A1\u7C7B\u578B", "\u8D23\u4EFB\u5355\u4F4D", "\u72B6\u6001", "\u8BA1\u5212\u65F6\u95F4", "\u5B8C\u6210\u65F6\u95F4", "\u7ED3\u8BBA"].map(item => <span key={item}>{item}</span>)}</div>              {data.feedback.tasks.map(task => (<div key={task.id}>                  <span>{task.id}</span>                  <span>{task.name}</span>                  <span>{task.type}</span>                  <span>{task.owner}</span>                  <span>{task.status}</span>                  <span>{task.plan}</span>                  <span>{task.completed}</span>                  <span>{task.conclusion}</span>                </div>))}            </div>          </article>        </section>      </main>    </div>);
}
