function OverviewPage() { const secondary = shuanDrilldownPages.filter(page => page.kind === "secondary"); const algorithms = shuanDrilldownPages.filter(page => page.kind === "algorithm"); return (<div className="drill-page tone-blue">      <DrillContentHeader eyebrow="铚€瀹夐页Av3" title="下钻页面框架总览" description="首页作为固定底稿保留在下层，二级页和三级页统一以覆盖层方式叠加在内容区，不再单独绘制全局顶部菜单。" icon={<GitBranch aria-hidden="true"/>} actions={<a href={routeHref("shuan-home-command-v3")}><ArrowLeft aria-hidden="true"/>返回首页 Av3</a>}/>      <section className="drill-overview-block">        <h2>二级下钻页面</h2>        <div className="drill-card-grid">          {secondary.map(page => { const Icon = getPageIcon(page); return (<a key={page.id} className={`drill-nav-card tone-${page.tone}`} href={routeHref(page.id)}>                <Icon aria-hidden="true"/>                <strong>{page.title}</strong>                <span>{page.scenario}</span>              </a>); })}        </div>      </section>      <section className="drill-overview-block">        <h2>打非治违三级算法页面</h2>        <div className="drill-card-grid compact">          {algorithms.map(page => { const Icon = getPageIcon(page); return (<a key={page.id} className={`drill-nav-card tone-${page.tone}`} href={routeHref(page.id)}>                <Icon aria-hidden="true"/>                <strong>{page.title}</strong>                <span>{page.scenario}</span>              </a>); })}        </div>      </section>    </div>); }
export function ShuanDrilldownContent({ pageId, onExit }: {
    pageId: string;
    onExit?: (pageId?: string) => void;
}) {
    if (pageId === "shuan-home-command-v3-coal-quantity-comparison-clue") {
        return <CoalQuantityComparisonCluePage onExit={onExit}/>;
    }
    if (pageId === shuanDataGovernanceData.route) {
        return <DataGovernancePage onExit={onExit}/>;
    }
    if (pageId === "shuan-home-command-v3-wireframes") {
        return <OverviewPage />;
    }
    if (pageId === "shuan-home-command-v3-production-status") {
        return <CoalBasicStatisticsPageV2 />;
    }
    if (pageId === "shuan-home-command-v3-production-operation") {
        return <ProductionOperationPage onExit={onExit}/>;
    }
    if (pageId === "shuan-home-command-v3-personnel-safety") {
        return <PersonnelSafetyPage onExit={onExit}/>;
    }
    if (pageId === "shuan-home-command-v3-video-dispatch") {
        return <VideoDispatchPage />;
    }
    if (pageId === "shuan-home-command-v3-illegal-algorithms") {
        return <IllegalCluePage />;
    }
    if (pageId === "shuan-home-command-v3-daily-regulation") {
        return <DailyRegulationOverviewPage />;
    }
    if (pageId === shuanRiskControlData.route) {
        return <RiskControlPage />;
    }
    if (pageId === shuanDangerousWorkReportData.route) {
        return <DangerousWorkReportPage onExit={onExit}/>;
    }
    if (pageId === shuanLicenseExpiryReminderData.route) {
        return <LicenseExpiryReminderPage />;
    }
    if (pageId === shuanMajorHazardReminderData.route) {
        return <MajorHazardReminderPage />;
    }
    if (pageId === shuanHiddenDangerData.route) {
        return <HiddenDangerManagementPage />;
    }
    if (pageId === shuanRectificationReviewData.route) {
        return <RectificationReviewPage />;
    }
    if (pageId === shuanCountyInspectionData.route) {
        return <CountyInspectionPage onExit={onExit}/>;
    }
    if (pageId === "guard-hidden-risk-agent-detail") {
        return <RiskAgentDetailPage />;
    }
    if (pageId === "shuan-home-command-v3-illegal-disposal-city-analysis") {
        return <IllegalCityAnalysisPage onExit={onExit}/>;
    }
    if (pageId === shuanProvinceSupervisionData.route) {
        return <ProvinceSupervisionPage />;
    }
    if (pageId === shuanHiddenFaceMineProfileData.route) {
        return <HiddenFaceMineProfilePage />;
    }
    if (shuanIllegalCampaignModules.some(item => item.route === pageId)) {
        return <IllegalCampaignReferenceV2Page />;
    }
    const page = shuanDrilldownPages.find(item => item.id === pageId);
    return page ? <DetailPage page={page}/> : <OverviewPage />;
}
export function ShuanDrilldownPage({ pageId }: {
    pageId: string;
}) { return (<DrilldownFrame pageId={pageId}>      <ShuanDrilldownContent pageId={pageId}/>    </DrilldownFrame>); }
